var minimumFuelCost = function(roads, seats) {
    const n = roads.length + 1;
    const adj = Array.from({ length: n }, () => []);
    for (const [a, b] of roads) { adj[a].push(b); adj[b].push(a); }
    let fuel = 0;
    const order = [];
    const parent = new Array(n).fill(-1);
    const visited = new Array(n).fill(false);
    const stack = [0];
    visited[0] = true;
    while (stack.length) {
        const u = stack.pop();
        order.push(u);
        for (const v of adj[u]) {
            if (!visited[v]) { visited[v] = true; parent[v] = u; stack.push(v); }
        }
    }
    const people = new Array(n).fill(1);
    for (let i = order.length - 1; i >= 0; i--) {
        const u = order[i];
        if (parent[u] !== -1) {
            const cars = Math.ceil(people[u] / seats);
            fuel += cars;
            people[parent[u]] += people[u];
        }
    }
    return fuel;
};
